const form = $input.first().json;
const template = form.Template;

// Update these with your actual TemplateFox template IDs
// Find them at app.templatefox.com → Templates
const templateMap = {
  'Invoice': '',
  'Receipt': '',
  'Certificate': '',
  'Packing Slip': ''
};

const templateId = templateMap[template];
if (!templateId) {
  throw new Error(`Template "${template}" not configured. Update the template IDs in this Code node.`);
}

// Build template data from form fields
const data = {
  name: form['Recipient Name'],
  email: form['Recipient Email'],
  company_name: form['Company Name'] || '',
  amount: form['Amount'] || '',
  description: form['Description'] || '',
  date: new Date().toISOString().split('T')[0],
  document_number: `DOC-${Date.now().toString(36).toUpperCase()}`
};

return [{
  json: {
    templateId,
    templateName: template,
    data,
    recipientEmail: form['Recipient Email'],
    recipientName: form['Recipient Name']
  }
}];
